function beyond_working_hours_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('beyond_working_hours_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'approval_from' => Request::val('approval_from', 'CEO'),
		'days_remark' => Request::val('days_remark', ''),
		'start_datetime' => Request::datetime('start_datetime', ''),
		'end_datetime' => Request::datetime('end_datetime', ''),
		'reason_for_overtime' => Request::val('reason_for_overtime', ''),
		'details_of_work_done' => Request::val('details_of_work_done', ''),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'approval_remarks' => Request::val('approval_remarks', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('beyond_working_hours_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		beyond_working_hours_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function beyond_working_hours_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function beyond_working_hours_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('beyond_working_hours_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: beyond_working_hours_table_before_delete
	if(function_exists('beyond_working_hours_table_before_delete')) {
		$args = [];
		if(!beyond_working_hours_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `beyond_working_hours_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: beyond_working_hours_table_after_delete
	if(function_exists('beyond_working_hours_table_after_delete')) {
		$args = [];
		beyond_working_hours_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='beyond_working_hours_table' AND `pkValue`='{$selected_id}'", $eo);
}

function beyond_working_hours_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('beyond_working_hours_table', $selected_id, 'edit')) return false;

	$data = [
		'approval_from' => Request::val('approval_from', ''),
		'days_remark' => Request::val('days_remark', ''),
		'start_datetime' => Request::datetime('start_datetime', ''),
		'end_datetime' => Request::datetime('end_datetime', ''),
		'reason_for_overtime' => Request::val('reason_for_overtime', ''),
		'details_of_work_done' => Request::val('details_of_work_done', ''),
		'approval_status' => Request::val('approval_status', ''),
		'approval_remarks' => Request::val('approval_remarks', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	if($data['start_datetime'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Start Date & Time': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['end_datetime'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'End Date & Time': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('beyond_working_hours_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: beyond_working_hours_table_before_update
	if(function_exists('beyond_working_hours_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!beyond_working_hours_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'beyond_working_hours_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="beyond_working_hours_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('beyond_working_hours_table', $data['selectedID'], calculated_fields()['beyond_working_hours_table']);

	// hook: beyond_working_hours_table_after_update
	if(function_exists('beyond_working_hours_table_after_update')) {
		if($row = getRecord('beyond_working_hours_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!beyond_working_hours_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('beyond_working_hours_table', $selected_id);
}

